changeSet.sql:
CREATE TABLE IF NOT EXISTS message (
    id                  BIGINT      GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    chat_id             BIGINT      NOT NULL,
    sender_id           BIGINT      NOT NULL,
    content             TEXT,
    message_type        VARCHAR(20) NOT NULL DEFAULT 'TEXT',
    status              VARCHAR(20) NOT NULL DEFAULT 'SENT',
    message_client_id   VARCHAR(64) NOT NULL,
    created_at          TIMESTAMPTZ NOT NULL DEFAULT NOW()
);

COMMENT ON TABLE message IS 'Individual chat messages; immutable once persisted';
COMMENT ON COLUMN message.message_client_id IS 'Client-generated idempotency key for deduplication';
COMMENT ON COLUMN message.message_type IS 'TEXT | IMAGE | FILE';
COMMENT ON COLUMN message.status IS 'SENT | DELIVERED | READ';
